class Solution:
    def sortPermutation(self, nums):
        n = len(nums)
        if all(nums[i] == i for i in range(n)):
            return 0
        def feasible(k):
            parent = list(range(n))
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            for i in range(n):
                for j in range(i + 1, n):
                    if (nums[i] & nums[j]) == k:
                        parent[find(i)] = find(j)
            groups = {}
            for i in range(n):
                groups.setdefault(find(i), []).append(i)
            for idxs in groups.values():
                if set(idxs) != set(nums[i] for i in idxs):
                    return False
            return True
        maxv = max(nums)
        for k in range(maxv, -1, -1):
            if feasible(k):
                return k
        return 0

