class Solution:
    def sortPermutation(self, nums):
        n = len(nums)
        if all(nums[i] == i for i in range(n)):
            return 0
        cands = set([0])
        for i in range(n):
            for j in range(i + 1, n):
                cands.add(nums[i] & nums[j])
        def feasible(k):
            parent = list(range(n))
            def find(x):
                while parent[x] != x:
                    parent[x] = parent[parent[x]]
                    x = parent[x]
                return x
            for i in range(n):
                for j in range(i + 1, n):
                    if (nums[i] & nums[j]) == k:
                        parent[find(i)] = find(j)
            from collections import defaultdict
            groups = defaultdict(list)
            for i in range(n):
                groups[find(i)].append(i)
            for idxs in groups.values():
                if set(idxs) != set(nums[i] for i in idxs):
                    return False
            return True
        for k in sorted(cands, reverse=True):
            if feasible(k):
                return k
        return 0

