var sortPermutation = function(nums) {
    const n = nums.length;
    let sorted = true;
    for (let i = 0; i < n; i++) if (nums[i] !== i) { sorted = false; break; }
    if (sorted) return 0;
    const cands = new Set([0]);
    for (let i = 0; i < n; i++) for (let j = i + 1; j < n; j++) cands.add(nums[i] & nums[j]);
    const feasible = (k) => {
        const parent = Array.from({length: n}, (_, i) => i);
        const find = (x) => { while (parent[x] !== x) { parent[x] = parent[parent[x]]; x = parent[x]; } return x; };
        for (let i = 0; i < n; i++) for (let j = i + 1; j < n; j++) if ((nums[i] & nums[j]) === k) parent[find(i)] = find(j);
        const groups = new Map();
        for (let i = 0; i < n; i++) { const r = find(i); if (!groups.has(r)) groups.set(r, []); groups.get(r).push(i); }
        for (const idxs of groups.values()) {
            const a = new Set(idxs);
            const b = new Set(idxs.map(i => nums[i]));
            if (a.size !== b.size) return false;
            for (const v of a) if (!b.has(v)) return false;
        }
        return true;
    };
    const arr = [...cands].sort((a, b) => b - a);
    for (const k of arr) if (feasible(k)) return k;
    return 0;
};
